const fileContent = $input.first().json.stdout || '';
const project = $('Webhook').first().json.query.project;
const folder = $('Webhook').first().json.query.folder || `/root/projects/${project}`;

if (fileContent.trim() === 'FILE_NOT_FOUND') {
  return [{ json: { hasPlan: false, errorType: 'file_not_found', project, folder } }];
}

const planMatch = fileContent.match(/## Plan[\r\n]([\s\S]*?)(?=[\n]## |[\n]---|$)/m);
const plan = planMatch ? planMatch[1].trim() : '';

if (!plan) {
  return [{ json: { hasPlan: false, errorType: 'no_plan', project, folder } }];
}

const taskContent = `# Taak: ${project}\nGegenereerd op: ${new Date().toLocaleString('nl-NL')}\n\n---\n\n${plan}\n\n---\n\n> Verwijder of overschrijf dit bestand na voltooiing.`;
const base64Task = Buffer.from(taskContent).toString('base64');

return [{ json: { hasPlan: true, plan, project, folder, base64Task } }];

const url = $input.first().json.stdout.trim();
const project = $('Webhook').first().json.query.project;
if (!url) {
  return [{ json: { html: `<html><head><style>body{background:#0a0a0a;color:#e8e8e8;font-family:system-ui;display:flex;align-items:center;justify-content:center;height:100vh;flex-direction:column;gap:16px}</style></head><body><h2 style='color:#ff9800'>TASK.md aangemaakt</h2><p style='color:#666'>Geen Claude URL gevonden. Start de sessie handmatig voor <strong>${project}</strong>.</p></body></html>` } }];
}
return [{ json: { html: `<html><head><meta http-equiv="refresh" content="0; url=${url}"></head><body>Verbinding maken met Claude...</body></html>` } }];
